mapper.select:
SELECT si.id, si.drug_id, d.drug_name, si.batch_id, sb.batch_no, si.quantity, si.cost_price, si.total_amount, si.supplier_id, s.name AS supplier_name, si.operator_id, u.username AS operator_username, si.remark, si.create_time FROM stock_in_table si LEFT JOIN drug_table d ON si.drug_id = d.id LEFT JOIN stock_batch_table sb ON si.batch_id = sb.id LEFT JOIN supplier_table s ON si.supplier_id = s.id LEFT JOIN user_table u ON si.operator_id = u.id
AND si.drug_id = #{drugId}
AND si.supplier_id = #{supplierId}
AND DATE(si.create_time) >= #{startDate}
AND DATE(si.create_time) <= #{endDate}
ORDER BY si.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM stock_in_table si


        AND si.drug_id = #{drugId}


        AND si.supplier_id = #{supplierId}


        AND DATE(si.create_time) >= #{startDate}


        AND DATE(si.create_time) <= #{endDate}
